#include "interface.h"

#include <vector>

uint64_t delta_prefix_sum(const std::vector<uint32_t>& deltas, uint32_t base, int iters) {
  // Preserve baseline semantics: if iters <= 0, no work is done and 0 is returned.
  if (iters <= 0) return 0;

  const std::size_t n = deltas.size();
  if (n == 0) return 0;

  const uint32_t* ptr = deltas.data();

  uint64_t value = static_cast<uint64_t>(base);
  uint64_t sum = 0;

  std::size_t i = 0;
  // Unrolled accumulation: decode prefix and sum in one pass, no temporary storage.
  for (; i + 4 <= n; i += 4) {
    value += static_cast<uint64_t>(ptr[i + 0]);
    sum += value;
    value += static_cast<uint64_t>(ptr[i + 1]);
    sum += value;
    value += static_cast<uint64_t>(ptr[i + 2]);
    sum += value;
    value += static_cast<uint64_t>(ptr[i + 3]);
    sum += value;
  }
  for (; i < n; ++i) {
    value += static_cast<uint64_t>(ptr[i]);
    sum += value;
  }

  return sum;
}
